import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { WorkOrder } from '@/models/or';
import { url } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'workOrders',
    template: () => import('./work-order-list.html?raw'),
    data: () => ({
        user: getAuthenticatedUser(),
        nav: null as string | null,
        aside: null as string | null,
        loading: true,
        workOrders: [] as WorkOrder[],

        currentTab: 0,

        async init() {
            console.log('work-order-list@init');

            this.nav = await render(nav);
            this.aside = await render(aside);

            await this.loadWorkOrders();
        },

        async loadWorkOrders() {
            this.loading = true;

            try {
                if (this.$router.route === '/or/me') {
                    const mecs = await fetch(url(`/isiWeb/web/v1/empresas/01/mecanicos?usuario=${this.user.usuario}`), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                    });

                    const mecsResponse = await mecs.json();

                    const baseUrl = `/isiWeb/web/v1/empresas/01/ordenes-reparacion?mec=${mecsResponse.data[0].mec}`;
                    let fetchUrl = '';
                    switch (this.currentTab) {
                        case 0:
                            fetchUrl = baseUrl;
                            break;
                        case 1:
                            fetchUrl = `${baseUrl}&fecrep:eq=`;
                            break;
                        case 2:
                            fetchUrl = `${baseUrl}&fecrep:ne=`;
                            break;
                    }

                    const r = await fetch(url(fetchUrl), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                    });

                    const response = await r.json();

                    this.workOrders = response.data as WorkOrder[];
                }

                if (this.$router.route === '/or/list') {
                    const baseUrl = `/isiWeb/web/v1/empresas/01/ordenes-reparacion?almnro=${this.user.usuario}`;
                    let fetchUrl = '';
                    switch (this.currentTab) {
                        case 0:
                            fetchUrl = baseUrl;
                            break;
                        case 1:
                            fetchUrl = `${baseUrl}&fecrep:eq=`;
                            break;
                        case 2:
                            fetchUrl = `${baseUrl}&fecrep:ne=`;
                            break;
                    }
                    const r = await fetch(url(fetchUrl), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                    });

                    const response = await r.json();

                    this.workOrders = response.data as WorkOrder[];
                }
            } catch (error: any) {
                this.error = error.message;
            }

            this.loading = false;
        },

        async changeTab() {
            await this.loadWorkOrders();
        },
    }),
} as ComponentModule;
